; 魔女の隠れ家


name = 魔女の隠れ家Ｂ５
insideName = Ｂ５
upper = 魔女の隠れ家Ｂ４
lower = 魔女の隠れ家Ｂ６
level = 23
bgm = hideout
roof = stone
shadow = dark
sky = black
blank = rock
antiWarp = true

; 各パーツ
━ = stoney
… = halfy
　 = marble
❑ = cube
／ = door
☖ = arch
⧻ = fence
－ = pole
︻ = panel
㊤ = ladderu
㊦ = ladderd

